/**
 * AES-256-GCM encryption using Web Crypto API.
 * Edge Runtime compatible — no Node.js crypto.
 *
 * Wire format: base64(IV[12] + authTag[16] + ciphertext)
 * This format is backward-compatible with the previous Node.js implementation.
 */

const IV_LENGTH = 12;
const AUTH_TAG_LENGTH = 16;
const KEY_LENGTH = 32;

/**
 * Encryption error types
 */
export class EncryptionError extends Error {
  constructor(message: string, cause?: unknown) {
    super(message);
    this.name = "EncryptionError";
    this.cause = cause;
  }
}

export class DecryptionError extends Error {
  constructor(message: string, cause?: unknown) {
    super(message);
    this.name = "DecryptionError";
    this.cause = cause;
  }
}

function hexToBytes(hex: string): Uint8Array {
  if (hex.length % 2 !== 0 || !/^[0-9a-fA-F]*$/.test(hex)) {
    throw new Error("Invalid hex string");
  }
  const bytes = new Uint8Array(hex.length / 2);
  for (let i = 0; i < hex.length; i += 2) {
    bytes[i / 2] = Number.parseInt(hex.slice(i, i + 2), 16);
  }
  return bytes;
}

function base64ToBytes(b64: string): Uint8Array {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

function bytesToBase64(bytes: Uint8Array): string {
  let binary = "";
  for (const byte of bytes) {
    binary += String.fromCharCode(byte);
  }
  return btoa(binary);
}

function validateKey(key: string): Uint8Array {
  if (!key || typeof key !== "string") {
    throw new EncryptionError("Encryption key must be a non-empty string");
  }

  try {
    // Try hex first (preferred format: 64 hex chars = 32 bytes)
    const hexBytes = hexToBytes(key);
    if (hexBytes.length === KEY_LENGTH) {
      return hexBytes;
    }
  } catch {
    // Not valid hex, try base64
  }

  try {
    const b64Bytes = base64ToBytes(key);
    if (b64Bytes.length === KEY_LENGTH) {
      return b64Bytes;
    }
  } catch {
    // Not valid base64 either
  }

  throw new EncryptionError(
    `Encryption key must be ${KEY_LENGTH} bytes (64 hex chars or 44 base64 chars).`
  );
}

/**
 * Encrypts plaintext using AES-256-GCM
 *
 * Format: base64(iv + authTag + ciphertext)
 * - IV (12 bytes): Initialization vector (random, unique per encryption)
 * - Auth Tag (16 bytes): GCM authentication tag (prevents tampering)
 * - Ciphertext (variable): Encrypted data
 *
 * @param plaintext - The plaintext string to encrypt
 * @param key - Encryption key (32 bytes as hex or base64 string)
 * @returns Base64-encoded encrypted string (IV + Auth Tag + Ciphertext)
 */
export async function encrypt(plaintext: string, key: string): Promise<string> {
  if (!plaintext || typeof plaintext !== "string") {
    throw new EncryptionError("Plaintext must be a non-empty string");
  }

  try {
    const keyBytes = validateKey(key);
    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));

    const cryptoKey = await crypto.subtle.importKey(
      "raw",
      keyBytes as Uint8Array<ArrayBuffer>,
      "AES-GCM",
      false,
      ["encrypt"]
    );

    const plaintextBytes = new TextEncoder().encode(plaintext);
    const encrypted = new Uint8Array(
      await crypto.subtle.encrypt(
        { name: "AES-GCM", iv, tagLength: AUTH_TAG_LENGTH * 8 },
        cryptoKey,
        plaintextBytes
      )
    );

    // Web Crypto returns ciphertext || authTag
    // Our wire format is IV || authTag || ciphertext
    const ciphertext = encrypted.subarray(
      0,
      encrypted.length - AUTH_TAG_LENGTH
    );
    const authTag = encrypted.subarray(encrypted.length - AUTH_TAG_LENGTH);

    const result = new Uint8Array(
      IV_LENGTH + AUTH_TAG_LENGTH + ciphertext.length
    );
    result.set(iv, 0);
    result.set(authTag, IV_LENGTH);
    result.set(ciphertext, IV_LENGTH + AUTH_TAG_LENGTH);

    return bytesToBase64(result);
  } catch (error) {
    if (error instanceof EncryptionError) {
      throw error;
    }
    throw new EncryptionError("Failed to encrypt data", error);
  }
}

/**
 * Decrypts ciphertext encrypted with AES-256-GCM
 *
 * @param ciphertext - Base64-encoded encrypted string (from encrypt())
 * @param key - Encryption key (32 bytes as hex or base64 string)
 * @returns Decrypted plaintext string
 */
export async function decrypt(
  ciphertext: string,
  key: string
): Promise<string> {
  if (!ciphertext || typeof ciphertext !== "string") {
    throw new DecryptionError("Ciphertext must be a non-empty string");
  }

  try {
    const keyBytes = validateKey(key);
    const buffer = base64ToBytes(ciphertext);

    if (buffer.length < IV_LENGTH + AUTH_TAG_LENGTH) {
      throw new DecryptionError(
        "Ciphertext is too short - data may be corrupted"
      );
    }

    const iv = buffer.subarray(0, IV_LENGTH);
    const authTag = buffer.subarray(IV_LENGTH, IV_LENGTH + AUTH_TAG_LENGTH);
    const encrypted = buffer.subarray(IV_LENGTH + AUTH_TAG_LENGTH);

    // Web Crypto expects ciphertext || authTag
    const combined = new Uint8Array(encrypted.length + AUTH_TAG_LENGTH);
    combined.set(encrypted, 0);
    combined.set(authTag, encrypted.length);

    const cryptoKey = await crypto.subtle.importKey(
      "raw",
      keyBytes as Uint8Array<ArrayBuffer>,
      "AES-GCM",
      false,
      ["decrypt"]
    );

    const decrypted = await crypto.subtle.decrypt(
      {
        name: "AES-GCM",
        iv: iv as Uint8Array<ArrayBuffer>,
        tagLength: AUTH_TAG_LENGTH * 8,
      },
      cryptoKey,
      combined
    );

    return new TextDecoder().decode(decrypted);
  } catch (error) {
    if (error instanceof DecryptionError) {
      throw error;
    }
    if (error instanceof EncryptionError) {
      throw new DecryptionError(error.message, error);
    }

    // Prefer structured DOMException check (Web Crypto standard for AES-GCM auth failures),
    // fall back to message-based check for runtimes that surface it differently.
    const isOperationError =
      (error instanceof DOMException && error.name === "OperationError") ||
      (error instanceof Error &&
        (error.message.includes("OperationError") ||
          error.message.includes("The operation failed")));

    if (isOperationError) {
      throw new DecryptionError(
        "Authentication failed - data may be corrupted or key is incorrect",
        error
      );
    }

    throw new DecryptionError("Failed to decrypt data", error);
  }
}

/**
 * Generates a new encryption key suitable for AES-256-GCM
 *
 * @returns 32-byte key as hex string (64 characters)
 */
export function generateEncryptionKey(): string {
  const bytes = crypto.getRandomValues(new Uint8Array(KEY_LENGTH));
  return Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

/**
 * API Key cryptographic utilities
 *
 * Provides functions for:
 * - Generating API keys with the correct format
 * - Hashing keys using SHA-256
 * - Extracting key previews for display
 */

import { sha256Hex } from "@repo/app-providers";
import { nanoid } from "@repo/lib";

/**
 * Unified API key prefix for all Lightfast keys
 * Format follows industry conventions: sk-{vendor}-{secret}
 */
export const LIGHTFAST_API_KEY_PREFIX = "sk-lf-";

/**
 * Length of the random portion of the API key
 * 43 chars × 62-char alphabet = ~256 bits entropy
 */
export const API_KEY_SECRET_LENGTH = 43;

/**
 * Number of characters to show in the key preview
 */
export const API_KEY_PREVIEW_LENGTH = 4;

/**
 * Generate a new API key with the unified Lightfast format
 *
 * @param prefix - The prefix to use (default: "sk-lf-")
 * @returns The generated API key with ~256 bits of entropy
 *
 * @example
 * ```ts
 * const key = generateApiKey();  // "sk-lf-AbC123xYz456..."
 * ```
 */
export function generateApiKey(
  prefix: string = LIGHTFAST_API_KEY_PREFIX
): string {
  const keySecret = nanoid(API_KEY_SECRET_LENGTH);
  return `${prefix}${keySecret}`;
}

/**
 * Result from generateOrgApiKey containing all parts needed for storage
 */
export interface OrgApiKeyResult {
  /** Full API key (only returned once, never stored) */
  key: string;
  /** Key prefix (e.g., "sk-lf-") */
  prefix: string;
  /** Last 4 characters of the key secret (for display) */
  suffix: string;
}

/**
 * Generate a new organization API key, returning all parts for storage
 *
 * This is used for org-scoped API keys where we store
 * the prefix and suffix separately for display purposes.
 *
 * @returns Object with full key, prefix, and suffix (last 4 chars)
 *
 * @example
 * ```ts
 * const { key, prefix, suffix } = generateOrgApiKey();
 * // key: "REDACTED" (full key - return once)
 * // prefix: "sk-lf-"
 * // suffix: "Z789" (last 4 chars)
 * ```
 */
export function generateOrgApiKey(): OrgApiKeyResult {
  const keySecret = nanoid(API_KEY_SECRET_LENGTH);
  const key = `${LIGHTFAST_API_KEY_PREFIX}${keySecret}`;
  const suffix = keySecret.slice(-API_KEY_PREVIEW_LENGTH);

  return {
    key,
    prefix: LIGHTFAST_API_KEY_PREFIX,
    suffix,
  };
}

/**
 * Hash an API key using SHA-256
 *
 * This is used to:
 * - Store the key hash in the database (never store plaintext)
 * - Verify incoming keys by hashing and comparing
 *
 * @param key - The API key to hash
 * @returns Hex-encoded SHA-256 hash of the key
 *
 * @example
 * ```ts
 * const hash = hashApiKey("sk-lf-abc123...");
 * // Returns: "abc123...def456" (64 character hex string)
 * ```
 */
export function hashApiKey(key: string): string {
  return sha256Hex(key);
}

/**
 * Extract a preview of the API key for display purposes
 *
 * @param key - The full API key
 * @returns Preview string in format "sk-lf-...XXXX"
 */
export function extractKeyPreview(key: string): string {
  const suffix = key.slice(-API_KEY_PREVIEW_LENGTH);
  return `sk-lf-...${suffix}`;
}

/**
 * Validate that a string has the correct API key format
 *
 * @param key - The string to validate
 * @returns True if the key has the correct format
 */
export function isValidApiKeyFormat(key: string): boolean {
  // Must start with sk-lf-
  if (!key.startsWith(LIGHTFAST_API_KEY_PREFIX)) {
    return false;
  }

  // Must have correct length: prefix (6) + secret (43) = 49
  const expectedLength =
    LIGHTFAST_API_KEY_PREFIX.length + API_KEY_SECRET_LENGTH;
  return key.length === expectedLength;
}

